function resolveElName(id: string | null | undefined, eb: Record<string, Element>): string {
  if (!id) return '—';
  const e = eb[id];
  if (!e) return id;
  return 'name' in e && typeof (e as { name?: unknown }).name === 'string'
    ? ((e as { name: string }).name ?? id)
    : id;
}

