3517	export function buildDecalMesh(
3518	  decal: DecalElem,
3519	  parentMesh: THREE.Mesh,
3520	  imageAssetsById: Record<string, string>,
3521	): THREE.Mesh | null {
3522	  const url = imageAssetsById[decal.imageAssetId];
3523	  if (!url) return null;
3524	
3525	  const { u0, v0, u1, v1 } = decal.uvRect as {
3526	    u0: number;
3527	    v0: number;
3528	    u1: number;
3529	    v1: number;
3530	  };
3531	  const uSize = u1 - u0;
3532	  const vSize = v1 - v0;
3533	
3534	  parentMesh.geometry.computeBoundingBox();
3535	  const bb = parentMesh.geometry.boundingBox ?? new THREE.Box3();
3536	  const sizeX = bb.max.x - bb.min.x;
3537	  const sizeY = bb.max.y - bb.min.y;
3538	  const sizeZ = bb.max.z - bb.min.z;
