// ---------------------------------------------------------------------------
// §15.1.2 — Family editor form-type mesh builders
// ---------------------------------------------------------------------------

/**
 * Build a THREE.Mesh for a FamilyExtrusion (closed 2D polygon extruded by depthMm).
 * Profile is in the XY plane; extrusion direction is +Z.
 */
export function buildFamilyExtrusionMesh(form: FamilyExtrusion): THREE.Mesh {
  const pts = form.profilePoints;
  if (pts.length < 3 || form.depthMm <= 0) {
    return new THREE.Mesh(new THREE.BufferGeometry(), new THREE.MeshStandardMaterial());
  }
  const shape = new THREE.Shape();
  shape.moveTo(pts[0].x / 1000, pts[0].y / 1000);
  for (let i = 1; i < pts.length; i++) {
    shape.lineTo(pts[i].x / 1000, pts[i].y / 1000);
  }
  shape.closePath();
  const geo = new THREE.ExtrudeGeometry(shape, {
    depth: form.depthMm / 1000,
    bevelEnabled: false,
  });
  const mat = new THREE.MeshStandardMaterial({ color: 0xaaaaaa, roughness: 0.6, metalness: 0.0 });
  return new THREE.Mesh(geo, mat);
}

/**
 * Build a THREE.Mesh for a FamilyRevolve (profile in XZ plane revolved around Y axis).
 * Uses LatheGeometry with profile radii derived from profilePoints.x.
 */
export function buildFamilyRevolveMesh(form: FamilyRevolve): THREE.Mesh {
  const pts = form.profilePoints;
  if (pts.length < 2) {
    return new THREE.Mesh(new THREE.BufferGeometry(), new THREE.MeshStandardMaterial());
  }
  const phiLength = THREE.MathUtils.degToRad(
    Math.max(1, Math.min(360, form.angleDeg)),
  );
  const lathePoints = pts.map((p) => new THREE.Vector2(Math.abs(p.x) / 1000, p.y / 1000));
  const geo = new THREE.LatheGeometry(lathePoints, 32, 0, phiLength);
  const mat = new THREE.MeshStandardMaterial({ color: 0xaaaaaa, roughness: 0.6, metalness: 0.0 });
  return new THREE.Mesh(geo, mat);
}

