  try {
    geom = meshFromSweep({
      kind: 'sweep',
      pathLines,
      profile,
      profilePlane: 'normal_to_path_start',
    });
  } catch {
    return null;
  }
  const mesh = new THREE.Mesh(geom, frameMat);
