      <div className="flex items-center gap-2 py-0.5">
        <span className="text-xs text-muted w-28 shrink-0">Sill depth (mm)</span>
        <input
          type="number"
          className="w-20 text-xs bg-surface border border-border rounded px-1 py-0.5"
          defaultValue={el.sillDepthMm ?? 75}
          key={`${el.id}-sillDepth`}
          step={5}
          onBlur={(e) => {
            const v = Number(e.currentTarget.value);
            if (!isNaN(v) && v >= 0) winPropChange?.('sillDepthMm', v);
          }}
          data-testid="inspector-window-sill-depth"
        />
      </div>
      <div className="flex items-center gap-2 py-0.5">
        <span className="text-xs text-muted w-28 shrink-0">Glazing material</span>
        <select
          className="flex-1 text-xs bg-surface border border-border rounded px-1 py-0.5"
          value={el.glazingMaterialId ?? ''}
          onChange={(e) => winPropChange?.('glazingMaterialId', e.target.value || null)}
          data-testid="inspector-window-glazing-material"
        >
          <option value="">— Default glass —</option>
          {projectMaterials.map((m) => (
            <option key={m.id} value={m.id}>
              {m.name}
            </option>
          ))}
        </select>
      </div>
    </div>
  );
}

